import React, { useState } from 'react';
import { PROJECTS } from '../constants';
import { ProjectCategory, Project } from '../types';
import { Plus, X, ArrowUpRight } from 'lucide-react';

const CATEGORIES: ProjectCategory[] = ['All', '3D FOOH', '3D Product', 'VFX', 'AI Technical'];

const Projects: React.FC = () => {
  const [filter, setFilter] = useState<ProjectCategory>('All');
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);

  const filteredProjects = filter === 'All' 
    ? PROJECTS 
    : PROJECTS.filter(p => p.category === filter);

  return (
    <section id="projects" className="py-32 bg-dark relative overflow-hidden">

      {/* 3D Landscape Background */}
      <div className="absolute inset-0 z-0 pointer-events-none">
         <img 
            src="https://images.unsplash.com/photo-1614728853913-1e221165d770?q=80&w=2000&auto=format&fit=crop" 
            alt="3D Landscape" 
            className="w-full h-full object-cover opacity-15"
         />
         <div className="absolute inset-0 bg-gradient-to-b from-dark via-dark/95 to-dark"></div>
      </div>

      <div className="container mx-auto px-6 md:px-12 relative z-10">

        {/* Header */}
        <div className="flex flex-col lg:flex-row lg:items-end justify-between mb-20 gap-8">
             <h2 className="text-5xl md:text-8xl font-display font-black text-white tracking-tighter mix-blend-screen">
                WORKS
             </h2>
             <div className="flex flex-wrap gap-4">
                {CATEGORIES.map(cat => (
                  <button
                    key={cat}
                    onClick={() => setFilter(cat)}
                    className={`text-xs font-bold uppercase tracking-widest px-4 py-2 border transition-all duration-300 backdrop-blur-sm ${
                        filter === cat 
                        ? 'border-gold text-gold bg-black/50' 
                        : 'border-white/10 text-gray-500 hover:border-white hover:text-white bg-black/20'
                    }`}
                  >
                    {cat}
                  </button>
                ))}
             </div>
        </div>

        {/* Gallery Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-1">
          {filteredProjects.map((project, index) => (
            <div 
              key={project.id}
              onClick={() => setSelectedProject(project)}
              className="group relative aspect-[3/4] cursor-pointer overflow-hidden bg-gray-900 border border-white/5"
            >
              <img 
                src={project.thumbnail} 
                alt={project.title} 
                className="w-full h-full object-cover transition-all duration-700 grayscale group-hover:grayscale-0 group-hover:scale-105"
              />

              <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex flex-col justify-between p-6">
                 <div className="self-end text-white border border-white/20 p-2 rounded-full hover:bg-gold hover:border-gold hover:text-black transition-colors">
                    <ArrowUpRight size={20} />
                 </div>
                 <div>
                    <span className="text-gold text-[10px] font-bold tracking-widest uppercase mb-2 block">
                        {project.category}
                    </span>
                    <h3 className="text-2xl font-display font-bold text-white">
                        {project.title}
                    </h3>
                 </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Modal */}
      {selectedProject && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-0 md:p-12 bg-black/95 backdrop-blur-md">
           <div className="bg-dark w-full max-w-6xl h-full md:h-auto border border-white/10 flex flex-col md:flex-row relative shadow-2xl shadow-gold/10">
              <button 
                  onClick={() => setSelectedProject(null)}
                  className="absolute top-4 right-4 z-20 text-white hover:text-gold"
                >
                  <X size={32} />
              </button>

              <div className="w-full md:w-2/3 bg-black flex items-center justify-center relative group h-1/2 md:h-auto">
                 <img src={selectedProject.thumbnail} className="w-full h-full object-contain opacity-80" />
                 <div className="absolute inset-0 flex items-center justify-center">
                    <div className="w-20 h-20 border border-white/30 rounded-full flex items-center justify-center group-hover:border-gold group-hover:scale-110 transition-all">
                        <div className="w-0 h-0 border-t-[10px] border-t-transparent border-l-[15px] border-l-white border-b-[10px] border-b-transparent ml-1 group-hover:border-l-gold"></div>
                    </div>
                 </div>
              </div>

              <div className="w-full md:w-1/3 p-8 md:p-12 flex flex-col justify-between border-l border-white/10 h-1/2 md:h-auto bg-charcoal">
                 <div>
                    <h3 className="text-3xl md:text-4xl font-display font-bold text-white mb-4">{selectedProject.title}</h3>
                    <p className="text-gold text-xs font-bold tracking-widest uppercase mb-8">{selectedProject.category}</p>

                    <div className="space-y-6">
                        <div>
                            <span className="block text-gray-600 text-[10px] uppercase tracking-widest mb-1">Client</span>
                            <span className="text-white text-lg">{selectedProject.client || "Personal Project"}</span>
                        </div>
                        <div>
                            <span className="block text-gray-600 text-[10px] uppercase tracking-widest mb-1">Role</span>
                            <span className="text-white text-lg">Cinematic Designer / 3D Artist</span>
                        </div>
                        <div className="pt-4 border-t border-white/10">
                            <p className="text-gray-400 text-sm leading-relaxed">{selectedProject.description}</p>
                        </div>
                    </div>
                 </div>
              </div>
           </div>
        </div>
      )}
    </section>
  );
};

export default Projects;

